import React from 'react'
import ReactApexChart from 'react-apexcharts'
import './styles.css'

const ApexChart = () => {
  const [state, setState] = React.useState({
    series: [68],
    options: {
      chart: {
        height: 360,
        type: 'gauge',
      },
      plotOptions: {
        radialBar: {
          shape: 'needle',
          startAngle: -135,
          endAngle: 135,
          min: 0,
          max: 100,
          bands: [
            { from: 0, to: 30, color: '#FF4560' },
            { from: 30, to: 70, color: '#FEB019' },
            { from: 70, to: 100, color: '#00E396' },
          ],
          bandsStyle: {
            strokeWidth: '50%',
            gap: 1,
          },
          ticks: {
            show: true,
            major: {
              count: 11,
              length: 8,
              width: 2,
              color: '#334155',
              placement: 'outside',
            },
            minor: {
              count: 1,
              length: 4,
              width: 1,
              color: '#94A3B8',
              placement: 'outside',
            },
            labels: {
              show: true,
              offset: 6,
              fontSize: '11px',
              color: '#334155',
            },
          },
          needle: {
            color: '#0F172A',
            length: '60%',
            baseWidth: 6,
            tipWidth: 1,
          },
          hollow: {
            margin: 0,
            size: '70%',
          },
          dataLabels: {
            name: { show: false },
            value: {
              offsetY: 32,
              fontSize: '28px',
              fontWeight: 700,
              formatter: function (val) {
                return val
              },
            },
          },
        },
      },
      labels: ['Speed'],
    },
  })

  return (
    <div>
      <div id="chart">
        <ReactApexChart
          options={state.options}
          series={state.series}
          type="gauge"
          height={360}
        />
      </div>
    </div>
  )
}

export default ApexChart
